/**
 * API Route: Sync Structure Between Pages
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function POST(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const { id } = params;
    const body = await request.json();
    const { targetPageId, syncContent = false } = body;

    // Validation
    if (!targetPageId) {
      return NextResponse.json(
        { success: false, error: 'Target page ID is required' },
        { status: 400 }
      );
    }

    // دریافت صفحه مبدا (source)
    const sourcePage = await prisma.page.findUnique({
      where: { id }
    });

    if (!sourcePage) {
      return NextResponse.json(
        { success: false, error: 'Source page not found' },
        { status: 404 }
      );
    }

    // دریافت صفحه مقصد (target)
    const targetPage = await prisma.page.findUnique({
      where: { id: targetPageId }
    });

    if (!targetPage) {
      return NextResponse.json(
        { success: false, error: 'Target page not found' },
        { status: 404 }
      );
    }

    // بررسی اینکه هر دو صفحه در یک گروه باشند
    if (sourcePage.pageGroupId !== targetPage.pageGroupId) {
      return NextResponse.json(
        { success: false, error: 'Pages must be in the same group' },
        { status: 400 }
      );
    }

    if (!sourcePage.builderData) {
      return NextResponse.json(
        { success: false, error: 'Source page has no builder data' },
        { status: 400 }
      );
    }

    // Parse کردن builderData
    const sourceBuilderData = JSON.parse(sourcePage.builderData);
    const targetBuilderData = targetPage.builderData 
      ? JSON.parse(targetPage.builderData)
      : { sections: [] };

    // ایجاد map از سکشنهای target بر اساس ID
    const targetSectionsMap = new Map(
      targetBuilderData.sections?.map((s: any) => [s.id, s]) || []
    );

    // Sync کردن ساختار
    const syncedSections = sourceBuilderData.sections?.map((sourceSection: any) => {
      const targetSection = targetSectionsMap.get(sourceSection.id);

      if (syncContent || !targetSection) {
        // اگر syncContent فعال باشه یا سکشن در target وجود نداره، کل سکشن رو کپی کن
        return { ...sourceSection };
      } else {
        // فقط type, order, style رو sync کن، محتوا رو حفظ کن
        return {
          ...targetSection,
          type: sourceSection.type,
          order: sourceSection.order,
          style: sourceSection.style
        };
      }
    }) || [];

    // بهروزرسانی صفحه مقصد
    const updatedPage = await prisma.page.update({
      where: { id: targetPageId },
      data: {
        builderData: JSON.stringify({
          ...targetBuilderData,
          sections: syncedSections
        }),
        lastSyncedAt: new Date()
      }
    });

    return NextResponse.json({
      success: true,
      data: {
        page: updatedPage,
        syncedSections: syncedSections.length,
        message: 'Structure synced successfully'
      }
    });

  } catch (error) {
    console.error('Error syncing structure:', error);
    return NextResponse.json(
      {
        success: false,
        error: 'Failed to sync structure',
        message: error instanceof Error ? error.message : 'Unknown error'
      },
      { status: 500 }
    );
  }
}
